ToolUseBlock(id='toolu_01CHD6R26qI60ihBeoePW3jS', name='Write', input={'file_path': '/workspace/app/styles.css', 'content': "/* Flux — Flow Field Studio
   Design language: a dark, instrument-like control surface floating over a
   full-bleed generative canvas. Display type in Space Grotesk, all numeric
   readouts in JetBrains Mono. Both fonts are vendored locally (no CDN). */

/* ---- Vendored fonts (local woff2, variable axes) ---- */
@font-face {
  font-family: 'Space Grotesk';
  font-style: normal;
  font-weight: 300 700;
  font-display: swap;
  src: url('./assets/fonts/space-grotesk-latin-variable.woff2') format('woff2');
}
@font-face {
  font-family: 'JetBrains Mono';
  font-style: normal;
  font-weight: 400 700;
  font-display: swap;
  src: url('./assets/fonts/jetbrains-mono-latin-variable.woff2') format('woff2');
}

:root {
  --display: 'Space Grotesk', system-ui, -apple-system, Segoe UI, sans-serif;
  --mono: 'JetBrains Mono', ui-monospace, SFMono-Regular, Menlo, monospace;

  --ink: #f4f6fb;
  --ink-dim: #aab3c5;
  --ink-faint: #6c7689;

  --panel-bg: rgba(15, 18, 28, 0.72);
  --panel-border: rgba(255, 255, 255, 0.1);
  --panel-edge: rgba(255, 255, 255, 0.05);

  --accent: #7c8cf8;
  --accent-2: #34d3ee;
  --track: rgba(255, 255, 255, 0.12);
}

* {
  box-sizing: border-box;
}

html,
body {
  margin: 0;
  padding: 0;
  height: 100%;
  background: #060a14;
  color: var(--ink);
  font-family: var(--display);
  overflow: hidden;
}

#flux-canvas {
  position: fixed;
  inset: 0;
  display: block;
  width: 100vw;
  height: 100vh;
  z-index: 0;
}

/* When frozen for capture the body is pinned to the fixed render resolution so
   a full-page screenshot is exactly the canvas. */
body.is-frozen {
  width: 1920px;
  height: 1080px;
  overflow: hidden;
}

/* ---- Control panel ---- */
.panel {
  position: fixed;
  top: 28px;
  left: 28px;
  z-index: 10;
  width: 312px;
  padding: 22px 22px 18px;
  border-radius: 20px;
  background: var(--panel-bg);
  border: 1px solid var(--panel-border);
  box-shadow:
    0 1px 0 var(--panel-edge) inset,
    0 24px 60px -24px rgba(0, 0, 0, 0.7),
    0 8px 24px -16px rgba(0, 0, 0, 0.6);
  backdrop-filter: blur(18px) saturate(140%);
  -webkit-backdrop-filter: blur(18px) saturate(140%);
}

.panel__head {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 12px;
  margin-bottom: 18px;
}

.panel__brand {
  display: flex;
  align-items: center;
  gap: 12px;
}

.panel__glyph {
  width: 34px;
  height: 34px;
  border-radius: 11px;
  background:
    radial-gradient(120% 120% at 30% 20%, var(--accent-2), transparent 60%),
    linear-gradient(135deg, var(--accent), #b07cf8);
  box-shadow: 0 6px 18px -6px rgba(124, 140, 248, 0.8);
}

.panel__titles {
  line-height: 1;
}

.panel__title {
  margin: 0;
  font-size: 19px;
  font-weight: 700;
  letter-spacing: 0.22em;
}

.panel__subtitle {
  margin: 4px 0 0;
  font-size: 11px;
  font-weight: 500;
  letter-spacing: 0.16em;
  text-transform: uppercase;
  color: var(--ink-faint);
}

.status-pill {
  font-family: var(--mono);
  font-size: 10px;
  font-weight: 500;
  letter-spacing: 0.08em;
  text-transform: uppercase;
  padding: 5px 10px;
  border-radius: 999px;
  border: 1px solid var(--panel-border);
  color: var(--ink-dim);
  white-space: nowrap;
}

.status-pill[data-mode='live'] {
  color: #6ee7b7;
  border-color: rgba(110, 231, 183, 0.35);
  background: rgba(110, 231, 183, 0.08);
}

.status-pill[data-mode='frozen'] {
  color: #93c5fd;
  border-color: rgba(147, 197, 253, 0.35);
  background: rgba(147, 197, 253, 0.08);
}

/* ---- Readout strip ---- */
.panel__readout {
  display: grid;
  grid-template-columns: 1fr 1fr 1fr;
  gap: 8px;
  margin-bottom: 20px;
  padding: 12px;
  border-radius: 14px;
  background: rgba(255, 255, 255, 0.03);
  border: 1px solid var(--panel-edge);
}

.readout {
  display: flex;
  flex-direction: column;
  gap: 5px;
  min-width: 0;
}

.readout__label {
  font-size: 9px;
  font-weight: 600;
  letter-spacing: 0.14em;
  text-transform: uppercase;
  color: var(--ink-faint);
}

.readout__value {
  font-size: 14px;
  font-weight: 600;
  color: var(--ink);
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
}

.readout__value--mono {
  font-family: var(--mono);
  font-weight: 500;
}

/* ---- Controls ---- */
.control {
  margin-bottom: 16px;
}

.control__label {
  display: flex;
  align-items: baseline;
  justify-content: space-between;
  gap: 10px;
  margin-bottom: 9px;
  font-size: 12px;
  font-weight: 500;
  letter-spacing: 0.06em;
  text-transform: uppercase;
  color: var(--ink-dim);
}

.control__num {
  font-family: var(--mono);
  font-size: 12px;
  font-weight: 500;
  color: var(--ink);
  letter-spacing: 0;
  text-transform: none;
}

/* Custom range slider */
.control__range {
  -webkit-appearance: none;
  appearance: none;
  width: 100%;
  height: 4px;
  border-radius: 999px;
  background: var(--track);
  outline: none;
  cursor: pointer;
}

.control__range::-webkit-slider-thumb {
  -webkit-appearance: none;
  appearance: none;
  width: 16px;
  height: 16px;
  border-radius: 50%;
  background: var(--ink);
  border: 3px solid var(--accent);
  box-shadow: 0 2px 8px -2px rgba(124, 140, 248, 0.9);
  transition: transform 0.12s ease;
}

.control__range::-webkit-slider-thumb:hover {
  transform: scale(1.12);
}

.control__range::-moz-range-thumb {
  width: 16px;
  height: 16px;
  border-radius: 50%;
  background: var(--ink);
  border: 3px solid var(--accent);
  box-shadow: 0 2px 8px -2px rgba(124, 140, 248, 0.9);
}

.control__range:focus-visible {
  box-shadow: 0 0 0 3px rgba(124, 140, 248, 0.4);
}

/* Number input (Particles) — typed, Enter-committed, so a GUI agent can drive
   it without a drag action. */
.control__number {
  -webkit-appearance: none;
  appearance: none;
  width: 100%;
  padding: 11px 14px;
  font-family: var(--mono);
  font-size: 14px;
  font-weight: 500;
  color: var(--ink);
  background: rgba(255, 255, 255, 0.05);
  border: 1px solid var(--panel-border);
  border-radius: 12px;
  cursor: text;
}

.control__number:focus-visible {
  outline: none;
  border-color: var(--accent);
  box-shadow: 0 0 0 3px rgba(124, 140, 248, 0.3);
}

/* Select */
.select-wrap {
  position: relative;
}

.select-wrap::after {
  content: '';
  position: absolute;
  right: 14px;
  top: 50%;
  width: 8px;
  height: 8px;
  border-right: 2px solid var(--ink-dim);
  border-bottom: 2px solid var(--ink-dim);
  transform: translateY(-65%) rotate(45deg);
  pointer-events: none;
}

.control__select {
  -webkit-appearance: none;
  appearance: none;
  width: 100%;
  padding: 11px 36px 11px 14px;
  font-family: var(--display);
  font-size: 13px;
  font-weight: 500;
  color: var(--ink);
  background: rgba(255, 255, 255, 0.05);
  border: 1px solid var(--panel-border);
  border-radius: 12px;
  cursor: pointer;
}

.control__select:focus-visible {
  outline: none;
  border-color: var(--accent);
  box-shadow: 0 0 0 3px rgba(124, 140, 248, 0.3);
}

.control__select option {
  color: #11151f;
}

/* ---- Actions ---- */
.panel__actions {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 10px;
  margin-top: 20px;
}

.btn {
  font-family: var(--display);
  font-size: 13px;
  font-weight: 600;
  letter-spacing: 0.04em;
  padding: 11px 14px;
  border-radius: 12px;
  cursor: pointer;
  border: 1px solid transparent;
  transition:
    transform 0.1s ease,
    background 0.15s ease,
    border-color 0.15s ease;
}

.btn:active {
  transform: translateY(1px);
}

.btn--primary {
  color: #0a0e16;
  background: linear-gradient(135deg, var(--accent-2), var(--accent));
  box-shadow: 0 8px 22px -10px rgba(52, 211, 238, 0.8);
}

.btn--primary:hover {
  background: linear-gradient(135deg, #5ee0f5, #8c9bff);
}

.btn--ghost {
  color: var(--ink-dim);
  background: rgba(255, 255, 255, 0.04);
  border-color: var(--panel-border);
}

.btn--ghost:hover {
  color: var(--ink);
  background: rgba(255, 255, 255, 0.08);
}

.btn:focus-visible {
  outline: none;
  box-shadow: 0 0 0 3px rgba(124, 140, 248, 0.4);
}

/* ---- Footer note ---- */
.panel__foot {
  margin-top: 18px;
  padding-top: 14px;
  border-top: 1px solid var(--panel-edge);
  font-size: 10.5px;
  line-height: 1.5;
  color: var(--ink-faint);
}

/* ---- Responsive: tablet & mobile ---- */
@media (max-width: 720px) {
  .panel {
    top: auto;
    bottom: 16px;
    left: 16px;
    right: 16px;
    width: auto;
    max-height: 72vh;
    overflow-y: auto;
  }
}

/* In frozen capture mode the panel stays visible (it is static, deterministic
   HTML and does not affect canvas byte-stability) so the VS judge can score the
   control surface alongside the artwork. It is pinned at the fixed resolution
   along with the body. */
