  // trails exist so the canvas starts from the palette base color).
  clear(ctx) {
    const [r, g, b] = this.params.palette.background;
    ctx.fillStyle = `rgb(${r}, ${g}, ${b})`;
    ctx.fillRect(0, 0, this.width, this.height);
  }
}
